      "type": "string"
    },
    "sample_size": {
      "type": "integer",
      "minimum": 0
    },
    "group_values": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "group_id",
          "group_label",
          "value"
        ],
        "properties": {
          "group_id": {
            "type": "string"
          },
          "group_label": {
            "type": "string"
          },
          "sample_size": {
            "type": "integer",
